const fs = require('fs');
const path = require('path');

const textFileTypes = ['org', 'md', 'markdown', 'txt', 'html', 'xml', 'json', 'csv', 'py', 'js', 'java', 'go', 'rs'];
const binaryFileTypes = ['pdf', 'jpg', 'jpeg', 'png', 'webp'];
const validFileTypes = textFileTypes.concat(binaryFileTypes);

function isSupportedFileType(filePath) {
  const fileExtension = filePath.split('.').pop().toLowerCase();
  return validFileTypes.includes(fileExtension);
}

function processDirectory(filesToPush, folderPath) {
  try {
    const files = fs.readdirSync(folderPath, { withFileTypes: true });
    for (const file of files) {
      if (file.name.startsWith('.')) continue;
      const filePath = path.join(folderPath, file.name);
      if (file.isFile() && isSupportedFileType(filePath)) {
        filesToPush.push(filePath);
      }
      if (file.isDirectory()) {
        processDirectory(filesToPush, filePath);
      }
    }
  } catch (err) {
    console.error(`Error reading directory ${folderPath}:`, err.message);
  }
}

const filesToProcess = [];
const configuredFolders = $input.global.get('folders') || [];
const configuredFiles = $input.global.get('files') || [];

// Add individual files
for (const file of configuredFiles) {
  if (fs.existsSync(file.path)) {
    filesToProcess.push(file.path);
  }
}

// Process folders recursively
for (const folder of configuredFolders) {
  if (fs.existsSync(folder.path)) {
    processDirectory(filesToProcess, folder.path);
  }
}

return {
  filesToProcess: filesToProcess,
  lastSync: $input.global.get('lastSync') || []
};

const fs = require('fs');
const lastSync = $input.item.json.lastSync;
const filesToProcess = $input.item.json.filesToProcess;

function filenameToMimeType(filename) {
  const extension = filename.split('.').pop().toLowerCase();
  const mimeTypes = {
    'pdf': 'application/pdf',
    'png': 'image/png',
    'jpg': 'image/jpeg',
    'jpeg': 'image/jpeg',
    'webp': 'image/webp',
    'md': 'text/markdown',
    'org': 'text/org',
    'txt': 'text/plain',
    'json': 'application/json'
  };
  return mimeTypes[extension] || 'text/plain';
}

const binaryFileTypes = ['pdf', 'jpg', 'jpeg', 'png', 'webp'];
const filesDataToPush = [];

for (const file of filesToProcess) {
  try {
    const stats = fs.statSync(file);
    const syncedFile = lastSync.find(f => f.path === file);

    // Check if file has been modified since last sync
    if (!syncedFile || new Date(stats.mtime) > new Date(syncedFile.datetime)) {
      const encoding = binaryFileTypes.includes(file.split('.').pop()) ? 'binary' : 'utf8';
      const fileContent = fs.readFileSync(file, { encoding: encoding });
      const mimeType = filenameToMimeType(file) + (encoding === 'utf8' ? '; charset=UTF-8' : '');

      filesDataToPush.push({
        path: file,
        mimeType: mimeType,
        content: fileContent,
        modified: stats.mtime.toISOString()
      });
    }
  } catch (err) {
    console.error(`Error processing file ${file}:`, err.message);
  }
}

return {
  filesDataToPush: filesDataToPush,
  lastSync: lastSync
};

const filesToProcess = $input.item.json.filesToProcess;
const successfulFiles = $input.item.json.successfulFiles || filesToProcess;

const updatedLastSync = successfulFiles.map(file => ({
  path: file,
  datetime: new Date().toISOString()
}));

return {
  lastSync: updatedLastSync
};
